const items = $input.all();
const result = [];

for (const item of items) {
  try {
    let planData;

    // Parse the Gemini response
    if (item.json.message && item.json.message.content) {
      const content = item.json.message.content;
      // Remove markdown code blocks if present
      const cleanContent = content.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
      planData = JSON.parse(cleanContent);
    } else {
      throw new Error('Invalid response structure from Gemini');
    }

    // Validate required fields
    const requiredFields = ['projectScope', 'milestones', 'tasks', 'acceptanceCriteria', 'risks', 'timeline', 'escrowStructure'];
    const missingFields = requiredFields.filter(field => !planData[field]);

    if (missingFields.length > 0) {
      throw new Error(`Missing required fields: ${missingFields.join(', ')}`);
    }

    // Validate array fields
    if (!Array.isArray(planData.milestones) || planData.milestones.length === 0) {
      throw new Error('milestones must be a non-empty array');
    }
    if (!Array.isArray(planData.tasks) || planData.tasks.length === 0) {
      throw new Error('tasks must be a non-empty array');
    }
    if (!Array.isArray(planData.escrowStructure) || planData.escrowStructure.length === 0) {
      throw new Error('escrowStructure must be a non-empty array');
    }

    // Validate timeline structure
    if (!planData.timeline.optimistic || !planData.timeline.realistic || !planData.timeline.conservative) {
      throw new Error('timeline must contain optimistic, realistic, and conservative estimates');
    }

    result.push({
      json: {
        valid: true,
        planData: planData,
        originalInput: $('Webhook Trigger').first().json.body
      }
    });
  } catch (error) {
    result.push({
      json: {
        valid: false,
        error: error.message,
        originalInput: $('Webhook Trigger').first().json.body
      }
    });
  }
}

return result;

