const milestones = $("Milestone ID Generator").first().json.milestones;
const planData = $("Milestone ID Generator").first().json.planData;
const complexityEstimate = $("Milestone ID Generator").first().json.complexityEstimate;
const totalBudget = $("Webhook Trigger").first().json.body.budget;
const riskData = $input.first().json.message?.content ? JSON.parse($input.first().json.message.content.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim()) : {};

const totalAllocated = planData.milestones.reduce((sum, m) => sum + (m.budgetAllocation || 0), 0);

const escrowStructure = milestones.map((milestone, index) => {
  const proportion = (planData.milestones[index].budgetAllocation || 0) / totalAllocated;
  const allocatedBudget = Math.round(totalBudget * proportion);

  return {
    milestoneId: milestone.milestoneId,
    milestoneName: milestone.name,
    escrowAmount: allocatedBudget,
    releaseConditions: milestone.deliverables || [],
    approvalRequired: true,
    disputeEscalationDays: 7,
    autoReleaseEnabled: false
  };
});

const finalTotal = escrowStructure.reduce((sum, e) => sum + e.escrowAmount, 0);
if (finalTotal !== totalBudget) {
  escrowStructure[escrowStructure.length - 1].escrowAmount += (totalBudget - finalTotal);
}

return [{
  json: {
    planData: planData,
    milestones: milestones,
    complexityEstimate: complexityEstimate,
    riskFactors: riskData,
    escrowStructure: escrowStructure,
    totalBudget: totalBudget
  }
}];

