const tasksData = $("Task Generator").first().json.message?.content ? JSON.parse($("Task Generator").first().json.message.content.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim()) : {};
const githubAuditData = $("GitHub Audit Requirement Generator").first().json.message?.content ? JSON.parse($("GitHub Audit Requirement Generator").first().json.message.content.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim()) : {};
const scopeChangeData = $("Scope Change Analyzer Agent").first().json.message?.content ? JSON.parse($("Scope Change Analyzer Agent").first().json.message.content.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim()) : {};
const traceabilityRecords = $("Store Traceability MongoDB").first().json.traceabilityRecords || [];
const originalInput = $("Webhook Trigger").first().json.body;
const timeline = escrowData.planData.timeline;

const today = new Date();
const optimisticDate = new Date(today);
optimisticDate.setDate(optimisticDate.getDate() + timeline.optimistic);
const realisticDate = new Date(today);
realisticDate.setDate(realisticDate.getDate() + timeline.realistic);
const conservativeDate = new Date(today);
conservativeDate.setDate(conservativeDate.getDate() + timeline.conservative);

const version = `v${Date.now()}`;
const planningConfidence = Math.min(95, Math.max(60, 100 - (escrowData.riskFactors.overallRiskScore || 0) * 0.4));

const projectPlan = {
  version: version,
  createdAt: today.toISOString(),
  clientId: originalInput.clientId,
  merchantId: originalInput.merchantId,
  projectDescription: originalInput.projectDescription,
  projectScope: escrowData.planData.projectScope,
  requirementsBreakdown: requirementsData,
  complexityEstimate: complexityEstimate,
  requirementTraceability: traceabilityRecords,
  milestones: escrowData.milestones,
  tasks: tasksData.tasks || [],
  criticalPath: tasksData.criticalPath || [],
  totalEstimatedHours: tasksData.totalEstimatedHours || 0,
  riskFactors: escrowData.riskFactors,
  escrowStructure: escrowData.escrowStructure,
  githubAuditRequirements: githubAuditData,
  scopeChangeAnalysis: scopeChangeData,
  acceptanceCriteria: escrowData.planData.acceptanceCriteria,
  timeline: {
    ...timeline,
    optimisticDelivery: optimisticDate.toISOString().split('T')[0],
    realisticDelivery: realisticDate.toISOString().split('T')[0],
    conservativeDelivery: conservativeDate.toISOString().split('T')[0],
    startDate: today.toISOString().split('T')[0]
  },
  budgetAllocation: {
    totalBudget: escrowData.totalBudget,
    milestoneAllocations: escrowData.escrowStructure,
    contingencyRecommended: escrowData.riskFactors.recommendedContingencyBudget || 10
  },
  planningConfidence: planningConfidence,
  status: "draft"
};

return [{
  json: {
    projectPlan: projectPlan,
    originalInput: originalInput
  }
}];

const requirementsData = $("Milestone ID Generator").first().json.requirementsBreakdown;
const milestones = $input.first().json.milestones;
const tasksData = $("Task Generator").first().json.message?.content ? JSON.parse($("Task Generator").first().json.message.content.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim()) : { tasks: [] };

const traceabilityRecords = [];
let reqCounter = 1;

if (requirementsData.functionalRequirements) {
  requirementsData.functionalRequirements.forEach(req => {
    const requirementId = `REQ-${String(reqCounter).padStart(3, "0")}`;
    reqCounter++;

    const relatedMilestones = milestones.filter(m => 
      req.description && m.name && m.name.toLowerCase().includes(req.description.toLowerCase().split(' ')[0])
    ).map(m => m.milestoneId);

    const relatedTasks = tasksData.tasks.filter(t => 
      relatedMilestones.includes(t.milestoneId)
    ).map(t => t.taskId);

    traceabilityRecords.push({
      requirementId: requirementId,
      requirement: req.description,
      requirementType: "functional",
      priority: req.priority,
      milestoneIds: relatedMilestones,
      taskIds: relatedTasks,
      githubAuditRequirements: [],
      verificationStatus: "pending",
      createdAt: new Date().toISOString()
    });
  });
}

if (requirementsData.technicalRequirements) {
  requirementsData.technicalRequirements.forEach(req => {
    const requirementId = `REQ-${String(reqCounter).padStart(3, "0")}`;
    reqCounter++;

    traceabilityRecords.push({
      requirementId: requirementId,
      requirement: req.description,
      requirementType: "technical",
      category: req.category,
      milestoneIds: [],
      taskIds: [],
      githubAuditRequirements: [],
      verificationStatus: "pending",
      createdAt: new Date().toISOString()
    });
  });
}

return [{
  json: {
    traceabilityRecords: traceabilityRecords,
    escrowData: $input.first().json
  }
}];

